{action_set_definitions}: {
  "get_batch_context": {
    "description": "Retrieves metadata for the current production batch on a specific line, including batch ID, material sources, and start times.",
    "parameters": {
      "type": "object",
      "properties": {
        "line_id": {
          "type": "string",
          "description": "The identifier of the production line (e.g., 'LINE_B42')."
        }
      },
      "required": [
        "line_id"
      ]
    },
    "example_output": {
      "batch_id": "ECU-2023-VOLT-009",
      "material_lot": "Solder-Alpha-99X",
      "start_time": "2023-10-27T08:00:00Z"
    }
  },
  "get_defect_logs": {
    "description": "Retrieves detailed inspection records for quality anomalies detected on a specific component for a given batch.",
    "parameters": {
      "type": "object",
      "properties": {
        "line_id": {
          "type": "string",
          "description": "The production line identifier."
        },
        "batch_id": {
          "type": "string",
          "description": "The batch identifier retrieved from batch context."
        },
        "component_id": {
          "type": "string",
          "description": "The specific component reference (e.g., 'R102')."
        }
      },
      "required": [
        "line_id",
        "batch_id",
        "component_id"
      ]
    },
    "example_output": {
      "defect_type": "Tombstoning",
      "defect_count": 42,
      "inspection_timestamp": "2023-10-27T10:15:00Z",
      "failure_rate": "5.4%"
    }
  },
  "get_process_telemetry": {
    "description": "Retrieves high-resolution sensor data and operating parameters from specific machines (SPI, PnP, or Reflow) for a given time window.",
    "parameters": {
      "type": "object",
      "properties": {
        "line_id": {
          "type": "string",
          "description": "The production line identifier."
        },
        "system_type": {
          "type": "string",
          "enum": [
            "SPI",
            "PnP",
            "Reflow"
          ],
          "description": "The specific system to query: Solder Paste Inspection (SPI), Pick-and-Place (PnP), or Reflow Oven."
        },
        "start_time": {
          "type": "string",
          "description": "ISO timestamp to start data retrieval."
        },
        "component_id": {
          "type": "string",
          "description": "Optionally filter telemetry for a specific component location."
        }
      },
      "required": [
        "line_id",
        "system_type",
        "start_time"
      ]
    },
    "example_output": {
      "telemetry_data": [
        {
          "metric": "pad_a_volume_pct",
          "value": 110
        },
        {
          "metric": "pad_b_volume_pct",
          "value": 85
        },
        {
          "metric": "zone_4_temp",
          "value": 245.5
        }
      ]
    }
  },
  "get_maintenance_records": {
    "description": "Queries historical maintenance and repair logs for a specific production line to identify recent interventions or equipment wear.",
    "parameters": {
      "type": "object",
      "properties": {
        "line_id": {
          "type": "string",
          "description": "The production line identifier."
        },
        "lookback_days": {
          "type": "number",
          "description": "Number of days to look back in history."
        }
      },
      "required": [
        "line_id"
      ]
    },
    "example_output": {
      "logs": [
        {
          "date": "2023-10-25",
          "action": "Nozzle replacement on PnP head 2",
          "technician": "USR-99"
        }
      ]
    }
  },
  "submit_root_cause_analysis": {
    "description": "Submits the final technical root cause report including the specific metric out of tolerance and the recommended process adjustment.",
    "parameters": {
      "type": "object",
      "properties": {
        "root_cause_category": {
          "type": "string",
          "enum": [
            "Printing",
            "Placement",
            "Metallurgical/Thermal"
          ],
          "description": "The identified category of the defect."
        },
        "out_of_tolerance_metric": {
          "type": "string",
          "description": "The specific process parameter that deviated from the SOP."
        },
        "physical_mechanism": {
          "type": "string",
          "description": "Description of how the out-of-tolerance metric led to tombstoning (e.g., unbalanced wetting torque)."
        },
        "recommendation": {
          "type": "string",
          "description": "The data-backed adjustment required to resolve the issue."
        }
      },
      "required": [
        "root_cause_category",
        "out_of_tolerance_metric",
        "physical_mechanism",
        "recommendation"
      ]
    },
    "example_output": null
  }
}
